import React, { useEffect, useState } from "react";
import socket from "../socket";

function Player() {
  const [name, setName] = useState("");
  const [joined, setJoined] = useState(false);
  const [started, setStarted] = useState(false);
  const [questions, setQuestions] = useState([]);
  const [current, setCurrent] = useState(0);
  const [score, setScore] = useState(0);

  // ✅ Fetch questions
  useEffect(() => {
    fetch("http://localhost:5000/api/game")
      .then((res) => res.json())
      .then((data) => {
        console.log("Questions loaded:", data);
        setQuestions(data);
      })
      .catch((err) => console.log(err));
  }, []);

  // ✅ Socket listeners
  useEffect(() => {
    console.log("🎧 Player listening...");

    socket.on("gameStarted", () => {
      console.log("🔥 Game started received");
      setStarted(true);
    });

    socket.on("nextQuestion", (index) => {
      console.log("➡️ Next question:", index);
      setCurrent(index);
    });

    socket.on("updateScore", ({ player, total }) => {
      if (player === name) {
        setScore(total);
      }
    });

    return () => {
      socket.off("gameStarted");
      socket.off("nextQuestion");
      socket.off("updateScore");
    };
  }, [name]);

  // ✅ Join game
  const joinGame = () => {
    if (!name) {
      alert("Enter your name");
      return;
    }

    console.log("Joining game:", name);

    socket.emit("joinGame", name);
    setJoined(true);
  };

  // ✅ Answer question
  const answerQuestion = (option) => {
    socket.emit("answer", {
      player: name,
      answer: option,
      correctAnswer: questions[current]?.answer,
    });
  };

  return (
    <div style={{ padding: "20px" }}>
      <h1>🎮 Player Page</h1>

      {/* 🔐 JOIN SCREEN */}
      {!joined ? (
        <>
          <input
            type="text"
            placeholder="Enter your name"
            value={name}
            onChange={(e) => setName(e.target.value)}
          />
          <button onClick={joinGame}>Join Game</button>
        </>
      ) : !started ? (
        <h3>⏳ Waiting for host to start...</h3>
      ) : (
        <>
          <h2>Question {current + 1}</h2>
          <h3>{questions[current]?.question}</h3>

          {questions[current]?.options.map((opt, i) => (
            <button
              key={i}
              onClick={() => answerQuestion(opt)}
              style={{ display: "block", margin: "10px" }}
            >
              {opt}
            </button>
          ))}

          <h2>🏆 Score: {score}</h2>
        </>
      )}
    </div>
  );
}

export default Player;
